  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ── 1. Users ────────────────────────────────────────────────────────\n// Recruiters and admins who log in to the system.\nmodel User {\n  id           String   @id @default(uuid())\n  email        String   @unique\n  passwordHash String\n  name         String\n  role         Role     @default(RECRUITER)\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  // Relationships\n  jobs Job[]\n}\n\nenum Role {\n  ADMIN\n  RECRUITER\n}\n\n// ── 2. Jobs ─────────────────────────────────────────────────────────\n// Job openings created by recruiters.\nmodel Job {\n  id           String    @id @default(uuid())\n  title        String\n  description  String\n  requirements String? // Optional detailed requirements\n  department   String?\n  status       JobStatus @default(OPEN)\n\n  // Embedding for future AI job matching\n  embedding Float[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relationships\n  createdBy    String\n  user         User          @relation(fields: [createdBy], references: [id])\n  applications Application[]\n}\n\nenum JobStatus {\n  OPEN\n  CLOSED\n  DRAFT\n}\n\n// ── 3. Candidates ───────────────────────────────────────────────────\n// The permanent Talent Pool. Parsed candidate profiles.\nmodel Candidate {\n  id              String   @id @default(uuid())\n  email           String   @unique\n  name            String\n  phone           String?\n  skills          String[] // Array of skills parsed by AI\n  experienceYears Int?\n  currentCompany  String?\n  location        String?\n\n  // Embedding for fast similarity search during matching\n  embedding Float[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relationships\n  resumes      Resume[]\n  applications Application[]\n}\n\n// ── 4. Resumes ──────────────────────────────────────────────────────\n// Uploaded PDFs and their raw extracted data.\nmodel Resume {\n  id           String      @id @default(uuid())\n  fileName     String\n  filePath     String\n  rawText      String? // Text extracted by PyMuPDF\n  parsedData   Json? // Structured JSON from Gemini\n  parseStatus  ParseStatus @default(PROCESSING)\n  errorMessage String? // If parsing fails\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relationships\n  candidateId String? // Nullable initially until parsing links it to a candidate\n  candidate   Candidate? @relation(fields: [candidateId], references: [id])\n}\n\nenum ParseStatus {\n  PROCESSING\n  COMPLETED\n  NEEDS_REVIEW\n  FAILED\n}\n\n// ── 5. Applications ─────────────────────────────────────────────────\n// Connects a Candidate to a specific Job opening.\nmodel Application {\n  id String @id @default(uuid())\n\n  aiScore     Int? // 0-100 relevance score from Gemini\n  aiReasoning String? // Explanation of the score\n  status      AppStatus @default(NEW)\n  source      AppSource @default(MANUAL) // Did they apply manually or were they AI recommended?\n\n  appliedAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relationships\n  candidateId String\n  jobId       String\n  candidate   Candidate   @relation(fields: [candidateId], references: [id], onDelete: Cascade)\n  job         Job         @relation(fields: [jobId], references: [id], onDelete: Cascade)\n  interviews  Interview[]\n\n  @@unique([candidateId, jobId]) // A candidate can only apply once per job\n}\n\nenum AppStatus {\n  NEW\n  SHORTLISTED\n  INTERVIEWING\n  OFFERED\n  REJECTED\n}\n\nenum AppSource {\n  MANUAL\n  AI_RECOMMENDED\n}\n\n// ── 6. Interviews ───────────────────────────────────────────────────\n// Scheduled interviews and the feedback provided by the interviewer.\nmodel Interview {\n  id              String   @id @default(uuid())\n  scheduledAt     DateTime\n  durationMinutes Int      @default(60)\n  meetingLink     String?\n  interviewerName String\n\n  status InterviewStatus @default(SCHEDULED)\n\n  // Feedback (Merged into this table for simplicity)\n  rating         Int? // 1-5 rating\n  feedbackText   String?\n  recommendation HireRecommendation?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relationships\n  applicationId String\n  application   Application @relation(fields: [applicationId], references: [id], onDelete: Cascade)\n}\n\nenum InterviewStatus {\n  SCHEDULED\n  COMPLETED\n  CANCELLED\n}\n\nenum HireRecommendation {\n  STRONG_HIRE\n  HIRE\n  NO_HIRE\n}\n",
